//! parity-station-handoff — multi-station handoff parity test.
//!
//! HYPOTHESIS UNDER TEST
//! ---------------------
//! When a chunk's residual is produced by station 1 (layers 0..14) and the
//! resulting hidden state is handed to station 2 (layers 14..28) running in a
//! SEPARATE pipeline instance (independent KV caches, independent buffers),
//! the multi-station path may produce a DIFFERENT residual than the single
//! pipeline running all 28 layers. The kernel itself is bit-perfect for
//! chunked-vs-single (proven by parity-chunk-vs-single.rs); this binary
//! isolates the boundary between station 1 and station 2.
//!
//! TWO TEST CASES
//! --------------
//! TEST 1: 4 tokens (single chunk per station; minimal cross-chunk contamination)
//!   PATH A: pipeline_full
//!     embed → forward_range_chunk(0..28, start_pos=0, seq_len=4) → residual_A
//!   PATH B: pipeline_1 (layers 0..14) + pipeline_2 (layers 14..28)
//!     pipeline_1.embed → forward_range_chunk(0..14, start_pos=0, seq_len=4) → split
//!     pipeline_2.forward_range_chunk(input=split, 14..28, start_pos=0, seq_len=4) → residual_B
//!
//! TEST 2: 8 tokens, chunked 4+4 per station (compounds chunked + handoff)
//!   PATH A: pipeline_full
//!     embed(8) → forward_range_chunk(0..28, start_pos=0, seq_len=4)
//!              + forward_range_chunk(0..28, start_pos=4, seq_len=4)  → residual_A (last 4)
//!   PATH B: station 1 + station 2 (independent pipelines)
//!     station1: forward_range_chunk(0..14, 0, 4) then (0..14, 4, 4) → split (last 4)
//!     station2: forward_range_chunk(input=split_chunk_0, 14..28, 0, 4)
//!             + forward_range_chunk(input=split_chunk_1, 14..28, 4, 4) → residual_B (last 4)
//!
//! PASS = cos > 0.99999, max-abs < 1e-3.
//!
//! Usage:
//!   cargo run --release --bin parity-station-handoff -- /tmp/qwen-coder-7b.knot

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    for i in 0..a.len() {
        let av = a[i] as f64;
        let bv = b[i] as f64;
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        return 0.0;
    }
    (dot / denom) as f32
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut m = 0.0f32;
    for i in 0..a.len() {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn mean_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut s = 0.0f64;
    for i in 0..a.len() {
        s += (a[i] - b[i]).abs() as f64;
    }
    (s / a.len() as f64) as f32
}

fn finite_stats(name: &str, v: &[f32]) {
    let mut nan = 0usize;
    let mut inf = 0usize;
    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    let mut sum = 0.0f64;
    for &x in v {
        if x.is_nan() {
            nan += 1;
            continue;
        }
        if x.is_infinite() {
            inf += 1;
            continue;
        }
        if x < lo {
            lo = x;
        }
        if x > hi {
            hi = x;
        }
        sum += x as f64;
    }
    let mean = sum / v.len() as f64;
    println!(
        "       [{}] len={} nan={} inf={} range=[{:.4}, {:.4}] mean={:.4}",
        name,
        v.len(),
        nan,
        inf,
        lo,
        hi,
        mean
    );
}

fn pass_fail(cos: f32, mxa: f32) -> &'static str {
    if cos > 0.99999 && mxa < 1e-3 {
        "PASS"
    } else {
        "FAIL"
    }
}

fn compare(name: &str, a: &[f32], b: &[f32], hidden_dim: usize, seq_len: usize) -> (f32, f32, f32) {
    assert_eq!(a.len(), b.len(), "compare buffers differ in size");
    let cos = cosine(a, b);
    let mxa = max_abs_delta(a, b);
    let mna = mean_abs_delta(a, b);
    println!(
        "       [{}] cos={:.6}  max-abs-delta={:.6}  mean-abs-delta={:.6}  -> {}",
        name,
        cos,
        mxa,
        mna,
        pass_fail(cos, mxa)
    );
    // Per-token breakdown
    for t in 0..seq_len {
        let ta = &a[t * hidden_dim..(t + 1) * hidden_dim];
        let tb = &b[t * hidden_dim..(t + 1) * hidden_dim];
        let c = cosine(ta, tb);
        let mx = max_abs_delta(ta, tb);
        let mn = mean_abs_delta(ta, tb);
        println!(
            "         tok[{}] cos={:.6}  max-abs={:.6}  mean-abs={:.6}",
            t, c, mx, mn
        );
    }
    (cos, mxa, mna)
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err(format!(
            "usage: {} <knot.path>",
            args.first()
                .map(String::as_str)
                .unwrap_or("parity-station-handoff")
        ));
    }
    let knot_path = args[1].clone();

    println!("============================================================");
    println!(" parity-station-handoff");
    println!("   knot   : {}", knot_path);
    println!("============================================================");

    // Sanity-load to read config.
    let (hidden_dim, total_layers) = {
        let knot = KnotWeights::load(&knot_path)?;
        let cfg = knot.config.as_ref().ok_or("no config block in knot")?;
        println!(
            "[meta] hidden={} layers={} heads={} kv={} head_dim={} ffn={} vocab={} rope={}",
            cfg.hidden_dim,
            cfg.num_layers,
            cfg.num_heads,
            cfg.num_kv_heads,
            cfg.head_dim,
            cfg.intermediate_size,
            cfg.vocab_size,
            cfg.rope_theta,
        );
        (cfg.hidden_dim, cfg.num_layers)
    };

    let split_layer = total_layers / 2; // 14 for qwen-coder-7b (28 layers)
    println!(
        "[plan] split_layer={}  total_layers={}",
        split_layer, total_layers
    );

    // Hand-coded valid qwen2 token IDs (vocab=151,936). Same shape pneuma-think
    // chunks into. Not BOS/PAD/EOS — just arbitrary mid-vocab tokens.
    let tokens_4: Vec<u32> = vec![1234, 2345, 3456, 4567];
    let tokens_8: Vec<u32> = vec![1234, 2345, 3456, 4567, 5678, 6789, 7890, 8901];

    // ===========================================================
    // TEST 1: 4 tokens, single chunk per station.
    // ===========================================================
    println!("\n----- TEST 1: 4 tokens, single chunk per station -----");
    println!(
        "  PATH A: pipeline_full forward_range_chunk(0..{}, 0, 4)",
        total_layers
    );
    println!("  PATH B: pipeline_1 forward_range_chunk(0..{}, 0, 4) -> pipeline_2 forward_range_chunk(input, {}..{}, 0, 4)",
        split_layer, split_layer, total_layers);

    // PATH A: single pipeline, all layers, single call
    let t = Instant::now();
    let knot_a = KnotWeights::load(&knot_path)?;
    let mut pipeline_full = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    drop(knot_a);
    let emb_a = pipeline_full.embed_chunk(&tokens_4, 0)?;
    let residual_a_t1 = pipeline_full.forward_range_chunk(&emb_a, 0, total_layers, 0, 4)?;
    println!(
        "[A] full single-pipeline 0..{} ok in {} ms  out={}",
        total_layers,
        t.elapsed().as_millis(),
        residual_a_t1.len()
    );
    finite_stats("A", &residual_a_t1);

    // PATH B: two independent pipelines, station handoff
    let t = Instant::now();
    let mut pipeline_1 = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    let mut pipeline_2 = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    let emb_b = pipeline_1.embed_chunk(&tokens_4, 0)?;
    let split_residual_t1 = pipeline_1.forward_range_chunk(&emb_b, 0, split_layer, 0, 4)?;
    println!(
        "       [station1] forward_range_chunk(0..{}) ok  out={}",
        split_layer,
        split_residual_t1.len()
    );
    finite_stats("split", &split_residual_t1);
    let residual_b_t1 =
        pipeline_2.forward_range_chunk(&split_residual_t1, split_layer, total_layers, 0, 4)?;
    println!(
        "[B] station1+station2 ok in {} ms  out={}",
        t.elapsed().as_millis(),
        residual_b_t1.len()
    );
    finite_stats("B", &residual_b_t1);

    println!("[T1] residual_A vs residual_B parity (4 tokens):");
    let (cos_t1, mxa_t1, _) = compare("T1", &residual_a_t1, &residual_b_t1, hidden_dim, 4);

    // ===========================================================
    // TEST 2: 8 tokens, 4+4 chunked PER station. Compounds chunked
    // dispatch with station handoff.
    // ===========================================================
    println!("\n----- TEST 2: 8 tokens chunked 4+4, handoff between stations -----");
    println!(
        "  PATH A: pipeline_full does (0..{}, 0, 4) + (0..{}, 4, 4)",
        total_layers, total_layers
    );
    println!(
        "  PATH B: station1 does (0..{}, 0, 4) + (0..{}, 4, 4),",
        split_layer, split_layer
    );
    println!(
        "           station2 receives each split residual and runs ({}..{}, 0/4, 4)",
        split_layer, total_layers
    );

    // PATH A: single pipeline, all layers, two chunks of 4
    let t = Instant::now();
    let mut pipeline_full2 = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    let emb_a8 = pipeline_full2.embed_chunk(&tokens_8, 0)?;
    let chunk_a_0 = &emb_a8[0..4 * hidden_dim];
    let chunk_a_1 = &emb_a8[4 * hidden_dim..8 * hidden_dim];
    let _residual_a8_first =
        pipeline_full2.forward_range_chunk(chunk_a_0, 0, total_layers, 0, 4)?;
    let residual_a8_second =
        pipeline_full2.forward_range_chunk(chunk_a_1, 0, total_layers, 4, 4)?;
    println!(
        "[A] full chunked 4+4 ok in {} ms  out={}",
        t.elapsed().as_millis(),
        residual_a8_second.len()
    );
    finite_stats("A_tail", &residual_a8_second);

    // PATH B: station1 (chunked 4+4) → station2 (chunked 4+4 fed by split residuals)
    let t = Instant::now();
    let mut pipeline_1b = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    let mut pipeline_2b = NativeLlamaPipeline::new(knot_path.clone(), false, 0.9);
    let emb_b8 = pipeline_1b.embed_chunk(&tokens_8, 0)?;
    let chunk_b_0 = &emb_b8[0..4 * hidden_dim];
    let chunk_b_1 = &emb_b8[4 * hidden_dim..8 * hidden_dim];

    // Station 1 produces residuals for chunk 0 then chunk 1
    let split_chunk_0 = pipeline_1b.forward_range_chunk(chunk_b_0, 0, split_layer, 0, 4)?;
    let split_chunk_1 = pipeline_1b.forward_range_chunk(chunk_b_1, 0, split_layer, 4, 4)?;
    println!(
        "       [station1] both chunks done  out0={} out1={}",
        split_chunk_0.len(),
        split_chunk_1.len()
    );

    // Station 2 receives them in order and continues with its own KV cache
    let _residual_b8_first =
        pipeline_2b.forward_range_chunk(&split_chunk_0, split_layer, total_layers, 0, 4)?;
    let residual_b8_second =
        pipeline_2b.forward_range_chunk(&split_chunk_1, split_layer, total_layers, 4, 4)?;
    println!(
        "[B] station1+station2 chunked 4+4 ok in {} ms  out={}",
        t.elapsed().as_millis(),
        residual_b8_second.len()
    );
    finite_stats("B_tail", &residual_b8_second);

    println!("[T2] residual_A vs residual_B parity (last 4 tokens):");
    let (cos_t2, mxa_t2, _) = compare(
        "T2",
        &residual_a8_second,
        &residual_b8_second,
        hidden_dim,
        4,
    );

    // ===========================================================
    // SUMMARY
    // ===========================================================
    println!("\n============================================================");
    println!(" parity-station-handoff  SUMMARY");
    println!("============================================================");
    println!(
        "  TEST 1 (4 tokens, 1 chunk):          cos={:.6}  max-abs={:.6}  -> {}",
        cos_t1,
        mxa_t1,
        pass_fail(cos_t1, mxa_t1)
    );
    println!(
        "  TEST 2 (8 tokens, 4+4 chunked):      cos={:.6}  max-abs={:.6}  -> {}",
        cos_t2,
        mxa_t2,
        pass_fail(cos_t2, mxa_t2)
    );
    let overall = pass_fail(cos_t1.min(cos_t2), mxa_t1.max(mxa_t2));
    println!("  OVERALL: {}", overall);
    println!("============================================================");
    Ok(())
}
